pub trait LanguageProvider { fn name(&self) -> &str; fn get_comment_syntax(&self) -> &str; fn get_keywords(&self) -> Vec<&str>; } pub struct LanguageRegistry { pub providers: std::collections::HashMap<String, Box<dyn LanguageProvider>>, } impl LanguageRegistry { pub fn new() -> Self { Self { providers: std::collections::HashMap::new() } } pub fn register(&mut self, provider: Box<dyn LanguageProvider>) { self.providers.insert(provider.name().to_string(), provider); } }
